  const t = items[i].json.text;
  if (!t) continue;

  if (current.length === 0) startIndex = i;

  current.push(t);

  if (current.length === CHUNK_SIZE) {
    chunks.push({
      json: {
        chunk_index: chunks.length + 1,
        start_paragraph: startIndex + 1,
        end_paragraph: i + 1,
        id_doc_gpt: $('Create folder GPT').first().json.id,
        id_doc_cloude: $('Create folder CLOUDE').first().json.id,
        paragraphs: current,
        // текст одним блоком, но мы сохраним границы абзацев пустой строкой:
        source_text: current.join("\n\n"),
      },
    });
    current = [];
  }
}

