return {
  submittedAt: DateTime.local().setZone('Europe/Moscow')
}

const result = [];
const MAX_LINE = 5000;
let currentLine = 0;
let currentChunk = '';
let currentIndex = 1;
let lineCR = '\n\n';

if ($('Download file').first().binary.data.mimeType === 'text/plain') { lineCR = '\n' };
for (const item of $input.first().json.text.split(lineCR)) {
  currentLine ++;
  currentChunk += item + '\n\n';
  if (currentLine >= MAX_LINE) {
    result.push({ text: currentChunk, indexFile: currentIndex });
    currentChunk='';
    currentLine=0;
    currentIndex++;
  }
}
if (currentChunk.length) {
  result.push({ text: currentChunk, indexFile: currentIndex });
}

return result;

