// Нода: Code
// Тип входных данных: Binary

// Получаем бинарные данные файла
const binaryKey = Object.keys($input.item.binary)[0];

// Правильный способ получить Buffer в n8n v1.x
const buffer = await this.helpers.getBinaryDataBuffer(
  0,          // индекс item
  binaryKey   // имя бинарного свойства
);

// Читаем первые байты
const bytes = [...buffer.slice(0, 16)];

const binaryData = $input.item.binary[binaryKey];

function detectByMagicBytes(buf) {
  // PDF
  if (buf[0] === 0x25 && buf[1] === 0x50 &&
      buf[2] === 0x44 && buf[3] === 0x46) {
    return { type: 'pdf', mime: 'application/pdf', ext: 'pdf' };
  }

  // PNG
  if (buf[0] === 0x89 && buf[1] === 0x50 &&
      buf[2] === 0x4E && buf[3] === 0x47) {
    return { type: 'png', mime: 'image/png', ext: 'png' };
  }

  // JPEG
  if (buf[0] === 0xFF && buf[1] === 0xD8 && buf[2] === 0xFF) {
    return { type: 'jpeg', mime: 'image/jpeg', ext: 'jpg' };
  }

  // GIF
  if (buf[0] === 0x47 && buf[1] === 0x49 && buf[2] === 0x46) {
    return { type: 'gif', mime: 'image/gif', ext: 'gif' };
  }

  // WEBP (RIFF....WEBP)
  if (buf[0] === 0x52 && buf[1] === 0x49 &&
      buf[2] === 0x46 && buf[3] === 0x46 &&
      buf[8] === 0x57 && buf[9] === 0x45 &&
      buf[10] === 0x42 && buf[11] === 0x50) {
    return { type: 'webp', mime: 'image/webp', ext: 'webp' };
  }

  // ZIP-based форматы: DOCX, XLSX, PPTX
  if (buf[0] === 0x50 && buf[1] === 0x4B &&
      buf[2] === 0x03 && buf[3] === 0x04) {
    // Уточняем тип по MIME из метаданных если есть
    const mime = binaryData.mimeType || '';
    if (mime.includes('wordprocessingml') || mime.includes('docx')) {
      return { type: 'docx', mime: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', ext: 'docx' };
    }
    if (mime.includes('spreadsheetml') || mime.includes('xlsx')) {
      return { type: 'xlsx', mime: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', ext: 'xlsx' };
    }
    if (mime.includes('presentationml') || mime.includes('pptx')) {
      return { type: 'pptx', mime: 'application/vnd.openxmlformats-officedocument.presentationml.presentation', ext: 'pptx' };
    }return { type: 'zip', mime: 'application/zip', ext: 'zip' };
  }

  // DOC / XLS старый формат (OLE2)
  if (buf[0] === 0xD0 && buf[1] === 0xCF &&
      buf[2] === 0x11 && buf[3] === 0xE0) {
    const mime = binaryData.mimeType || '';
    if (mime.includes('excel') || mime.includes('xls')) {
      return { type: 'xls', mime: 'application/vnd.ms-excel', ext: 'xls' };
    }
    return { type: 'doc', mime: 'application/msword', ext: 'doc' };
  }

  // MP3 (ID3)
  if (buf[0] === 0x49 && buf[1] === 0x44 && buf[2] === 0x33) {
    return { type: 'mp3', mime: 'audio/mpeg', ext: 'mp3' };
  }

  // MP4 (ftyp at offset 4)
  if (buf[4] === 0x66 && buf[5] === 0x74 &&
      buf[6] === 0x79 && buf[7] === 0x70) {
    return { type: 'mp4', mime: 'video/mp4', ext: 'mp4' };
  }

  // HTML
  const textStart = buf.toString('utf8', 0, 15).toLowerCase().trim();
  if (textStart.startsWith('<!doctype html') ||
      textStart.startsWith('<html')) {
    return { type: 'html', mime: 'text/html', ext: 'html' };
  }

  // XML
  if (textStart.startsWith('<?xml')) {
    return { type: 'xml', mime: 'application/xml', ext: 'xml' };
  }

  // JSON
  if (textStart.startsWith('{') || textStart.startsWith('[')) {
    return { type: 'json', mime: 'application/json', ext: 'json' };
  }

  // Fallback — по MIME из метаданных
  if (binaryData.mimeType) {
    const mimeMap = {
      'text/plain':{ type: 'txt',ext: 'txt'  },
      'text/csv':       { type: 'csv',      ext: 'csv'},
      'text/markdown':  { type: 'markdown', ext: 'md'   },
    };
    const found = mimeMap[binaryData.mimeType];
    if (found) return { ...found, mime: binaryData.mimeType };
  }

  // Попытка определить текстовый файл
  const isText = buf.every(b => b >= 0x09 && b <= 0x7E || b >= 0x80);
  if (isText) {
    return { type: 'txt', mime: 'text/plain', ext: 'txt' };
  }

  return { type: 'unknown', mime: 'application/octet-stream', ext: '' };
}

const detected = detectByMagicBytes(bytes);

// Категория для роутинга
const categories = {
  pdf:'document',
  doc:      'document',
  docx:     'document',
  xls:      'spreadsheet',
  xlsx:     'spreadsheet',
  pptx:     'presentation',
  txt:      'text',
  csv:      'text',
  markdown: 'text',
  html:     'text',
  xml:      'text',
  json:     'text',
  jpeg:     'image',
  png:      'image',
  gif:      'image',
  webp:     'image',
  mp3:      'audio',
  mp4:      'video',
  zip:      'archive',
  unknown:  'unknown'
};

return {
  json: {
    ...detected,
    category: categories[detected.type] || 'unknown',
    fileName: binaryData.fileName || 'unknown',
    fileSize: buffer.length,
    fileSizeKb: Math.round(buffer.length / 1024),
    canParseToText: ['document', 'spreadsheet', 'text', 'image'].includes(
      categories[detected.type]
    ),
    binaryKey: binaryKey
  },
  binary: $input.item.binary
};

// Нода: Code
// Входные данные: items[0].json.text

const text = $input.item.json.text || '';

function detectLanguage(text) {if (!text || text.trim().length === 0) {
    return { language: 'unknown', confidence: 0, script: 'none' };
  }

  // Счётчики символов по алфавитам
  const counts = {
    korean:0,
    cyrillic: 0,
    latin:    0,
    japanese: 0,
    chinese:  0,arabic:   0,
    total:    0
  };

  for (const char of text.substr(0, 200)) {
    const code = char.charCodeAt(0);

    // Корейский (хангыль)
    if ((code >= 0xAC00 && code <= 0xD7AF) ||
        (code >= 0x1100 && code <= 0x11FF) ||
        (code >= 0x3130 && code <= 0x318F)) {
      counts.korean++;
      counts.total++;
    }
    // Кириллица (русский, украинский, болгарский и др.)
    else if (code >= 0x0400 && code <= 0x04FF) {
      counts.cyrillic++;
      counts.total++;
    }
    // Латиница
    else if ((code >= 0x0041 && code <= 0x005A) ||
             (code >= 0x0061 && code <= 0x007A)) {
      counts.latin++;
      counts.total++;
    }
    // Японский (хирагана + катакана)
    else if ((code >= 0x3040 && code <= 0x309F) ||
             (code >= 0x30A0 && code <= 0x30FF)) {
      counts.japanese++;
      counts.total++;
    }
    // Китайский (CJK)
    else if (code >= 0x4E00 && code <= 0x9FFF) {
      counts.chinese++;
      counts.total++;
    }
    // Арабский
    else if (code >= 0x0600 && code <= 0x06FF) {
      counts.arabic++;
      counts.total++;
    }}

  if (counts.total === 0) {
    return { language: 'unknown', confidence: 0, script: 'none' };
  }

  // Вычисляем процент каждого алфавита
  const percentages = {};
  for (const [key, val] of Object.entries(counts)) {
    if (key !== 'total') {
      percentages[key] = Math.round((val / counts.total) * 100);
    }
  }

  // Определяем доминирующий язык
  const dominant = Object.entries(percentages)
    .sort(([,a], [,b]) => b - a)[0];

  const langMap = {
    korean:   'ko',
    cyrillic: 'ru',
    latin:    'en',
    japanese: 'ja',
    chinese:  'zh',
    arabic:   'ar'
  };

  const nameMap = {
    korean:   'Корейский',
    cyrillic: 'Русский/Кириллица',
    latin:    'Английский/Латиница',
    japanese: 'Японский',
    chinese:  'Китайский',
    arabic:   'Арабский'
  };

  return {
    language: langMap[dominant[0]] || 'unknown',
    languageName: nameMap[dominant[0]] || 'Неизвестный',
    confidence: dominant[1],
    script: dominant[0],
    breakdown: percentages,
    isKorean:   percentages.korean   > 30,
    isRussian:  percentages.cyrillic > 30,
    isEnglish:  percentages.latin    > 30,
    isMixed:    Object.values(percentages).filter(v => v > 20).length > 1
  };
}

