// Извлекаем все li.list-item
function extractListItems(html) {
    const items = [];

    // Находим все li с классом list-item
    const liPattern = /<li[^>]+class="[^"]*list-item[^"]*"[^>]*>([\s\S]*?)<\/li>/gi;
    let liMatch;

    while ((liMatch = liPattern.exec(html)) !== null) {
        const liHtml = liMatch[0];
        const liContent = liMatch[1];

        // data-index
        const dataIndexMatch = liHtml.match(/data-index="(\d+)"/);
        const dataIndex = dataIndexMatch ? parseInt(dataIndexMatch[1]) : null;

        // wr-num
        const numMatch = liContent.match(/<div[^>]*class="wr-num"[^>]*>(\d+)<\/div>/);
        const number = numMatch ? parseInt(numMatch[1]) : null;

        // href из item-subject
        const hrefMatch = liContent.match(/<a[^>]+href="([^"]+)"[^>]*class="item-subject"/);
        const hrefMatch2 = liContent.match(/class="item-subject"[^>]*href="([^"]+)"/);
        const url = (hrefMatch && hrefMatch[1]) || (hrefMatch2 && hrefMatch2[1]) || '';

        // Заголовок — текст внутри item-subject без тегов
        const subjectMatch = liContent.match(/<a[^>]*class="item-subject"[^>]*>([\s\S]*?)<\/a>/);
        let title = '';
        if (subjectMatch) {
            title = subjectMatch[1]
                .replace(/<[^>]+>/g, '') // убираем теги
                .replace(/\s+/g, ' ')    // убираем лишние пробелы
                .trim();
        }

        // wr-date
        const dateMatch = liContent.match(/<div[^>]*class="wr-date[^"]*"[^>]*>([\s\S]*?)<\/div>/);
        const date = dateMatch
            ? dateMatch[1].replace(/\s+/g, ' ').trim()
            : '';

        // wr-good (лайки)
        const goodMatch = liContent.match(/<div[^>]*class="wr-good[^"]*"[^>]*>([\s\S]*?)<\/div>/);
        const likes = goodMatch
            ? parseInt(goodMatch[1].trim()) || 0
            : 0;

        // Комментарии
        const commentMatch = liContent.match(/<b>(\d+)<\/b>/);
        const comments = commentMatch ? parseInt(commentMatch[1]) : 0;

        items.push({
            dataIndex,
            number,
            title,
            url,
            date,
            likes,
            comments
        });
    }

    return items;
}

