// ─── Шаг 2: Находим div#novel_content ─────────────────

const startTagMatch = html.match(/<div[^>]+id="novel_content"[^>]*>/i);

if (!startTagMatch) {
    throw new Error('#novel_content не найден. Проверь HTML.');
}

const startTagStr = startTagMatch[0];
