// ─── Шаг 3: Находим закрывающий </div> по глубине ─────

let depth = 1;
let pos = contentStart;

while (pos < html.length && depth > 0) {
    if (html[pos] === '<') {

        // Открывающий <div ...>
        if (html.substring(pos, pos + 4) === '<div') {
            const nextChar = html[pos + 4];
            if (
                nextChar === ' ' ||
                nextChar === '\t' ||
                nextChar === '\n' ||
                nextChar === '\r' ||
                nextChar === '>'
            ) {
                depth++;
            }
        }

        // Закрывающий </div>
        else if (html.substring(pos, pos + 6) === '</div>') {
            depth--;
            if (depth === 0) break;
        }
    }
    pos++;
}

// Извлекаем содержимое novel_content
const content = html.substring(contentStart, pos);

console.log(`Длина content: ${content.length} символов`);
