// ─── Шаг 4: Вспомогательные функции ───────────────────

// Декодируем HTML entities
function decodeEntities(str) {
    return str
        .replace(/&nbsp;/gi,  ' ')
        .replace(/&amp;/gi,'&')
        .replace(/&lt;/gi,    '<')
        .replace(/&gt;/gi,    '>')
        .replace(/&quot;/gi,  '"')
        .replace(/&#39;/gi,   "'")
        .replace(/&apos;/gi,  "'")
        .replace(/&#(\d+);/g, (_, code) =>
            String.fromCharCode(parseInt(code, 10))
        )
        .replace(/&#x([0-9a-f]+);/gi, (_, hex) =>
            String.fromCharCode(parseInt(hex, 16))
        )
        .replace(/&[a-zA-Z]+;/g, ' '); // остальные entities
}

// Удаляем все HTML теги
function stripTags(str) {
    return str.replace(/<[^>]*>/g, '');
}

// Очищаем текст
function cleanText(str) {
    return decodeEntities(stripTags(str))
        .replace(/\s+/g, ' ')
        .trim();
}

// ─── Шаг 5: Извлекаем параграфы <p> ───────────────────

const paragraphs = [];
const pRegex = /<p[^>]*>([\s\S]*?)<\/p>/gi;
let match;

while ((match = pRegex.exec(content)) !== null) {
    const text = cleanText(match[1]);

    // Пропускаем пустые параграфы и только пробелы
    if (text && text.replace(/\s/g, '').length > 0) {
        paragraphs.push(text);
    }
}

console.log(`Параграфов найдено: ${paragraphs.length}`);

// ─── Шаг 6: Если параграфов нет — берём весь текст ────

if (paragraphs.length === 0) {
    console.log('Параграфы <p> не найдены — извлекаем весь текст');

    const allText = cleanText(content);

    return [{
        json: {
            fullText: allText,
